<?php use App\Core\Helpers as H;use App\Controllers\AdminWaitlistController;$statusCounts=array_column($counts,'count','status');?><section class="panel"><h1>Launch waitlist</h1><p><strong><?=number_format($total)?></strong> matching entries.</p><div class="status-counts" aria-label="Global waitlist status counts"><strong>Global status counts:</strong><?php foreach(['subscribed','invited','unsubscribed','suppressed'] as $s):?><span class="badge"><?=H::e(ucfirst($s))?>: <?=(int)($statusCounts[$s]??0)?></span><?php endforeach;?></div><p><a href="/admin/waitlist/export<?=$query?'?'.H::e($query):''?>">Export filtered CSV</a></p><form method="get" class="admin-filters"><input name="q" placeholder="Name, email, or business" value="<?=H::e($filters['q'])?>"><select name="interest_type"><option value="">All interests</option><?php foreach(['seller','buyer','both','tester'] as $v):?><option value="<?=$v?>" <?=$v===$filters['interest_type']?'selected':''?>><?=ucfirst($v)?></option><?php endforeach;?></select><select name="source"><option value="">All sources</option><?php foreach(['direct','homepage','seller','social','referral','campaign'] as $v):?><option value="<?=$v?>" <?=$v===$filters['source']?'selected':''?>><?=ucfirst($v)?></option><?php endforeach;?></select><select name="status"><option value="">All statuses</option><?php foreach(['subscribed','invited','unsubscribed','suppressed'] as $v):?><option value="<?=$v?>" <?=$v===$filters['status']?'selected':''?>><?=ucfirst($v)?></option><?php endforeach;?></select><button>Filter</button></form>
<div class="panel"><p><strong><?=$eligible?></strong> currently filtered, eligible, not-yet-invited subscribers can be queued.</p><?php if($eligible>0):?><form method="post" action="/admin/waitlist/launch-invite"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><input type="hidden" name="mode" value="filtered"><?php foreach($filters as $k=>$v):?><input type="hidden" name="<?=H::e($k)?>" value="<?=H::e($v)?>"><?php endforeach;?><label><input type="checkbox" name="confirm" value="1" required> Confirm this filtered bulk invitation</label><?php if(!$query):?><label><input type="checkbox" name="all_eligible" value="1" required> I explicitly intend to invite all eligible subscribers</label><?php endif;?><button>Queue filtered invitations</button></form><?php else:?><p class="muted">There are no eligible, not-yet-invited subscribers for this selection.</p><?php endif;?></div>
<?php if(!$entries):?><p class="muted">No waitlist entries match these filters.</p><?php else:?><div class="table-scroll"><table><thead><tr><th>Name</th><th>Email</th><th>Interest</th><th>Source</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach($entries as $e):?><tr><td><?=H::e($e['name'])?></td><td><?=H::e($e['email'])?></td><td><?=H::e(ucfirst($e['interest_type']))?></td><td><?=H::e(ucfirst($e['source']))?></td><td><?=H::e(ucfirst($e['status']))?></td><td><form method="post"><?php foreach($filters as $k=>$v):?><input type="hidden" name="<?=H::e($k)?>" value="<?=H::e($v)?>"><?php endforeach;?><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><input type="hidden" name="id" value="<?=(int)$e['id']?>"><label class="sr-only" for="status-<?=(int)$e['id']?>">Status for <?=H::e($e['name'])?></label><select id="status-<?=(int)$e['id']?>" name="status"><?php foreach(AdminWaitlistController::statusOptions($e['status']) as $s):?><option value="<?=$s?>" <?=$s===$e['status']?'selected':''?>><?=H::e($s===$e['status']?'No change — '.ucfirst($s):ucfirst($s))?></option><?php endforeach;?></select><button>Update</button></form><?php if(in_array($e['status'],['subscribed','invited'],true)&&!$e['invited_at']):?><form method="post" action="/admin/waitlist/launch-invite"><?php foreach($filters as $k=>$v):?><input type="hidden" name="<?=H::e($k)?>" value="<?=H::e($v)?>"><?php endforeach;?><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><input type="hidden" name="mode" value="individual"><input type="hidden" name="id" value="<?=(int)$e['id']?>"><button>Queue invite</button></form><?php endif;?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?><nav class="pagination"><?php if($page>1):?><a href="?<?=H::e(http_build_query(array_merge($filters,['page'=>$page-1])))?>">Previous</a><?php endif;?> <span>Page <?=$page?> of <?=$pages?></span> <?php if($page<$pages):?><a href="?<?=H::e(http_build_query(array_merge($filters,['page'=>$page+1])))?>">Next</a><?php endif;?></nav></section>
